# ─────────────────────────────────────────────────────────────────────────────

def plot_surface_3d(Z, title="Ocean surface", L=10.0, stride=1, zlim=None):
    Z = np.real(np.asarray(Z))
    Ny, Nx = Z.shape

    x = np.linspace(-L/2, L/2, Nx)
    y = np.linspace(-L/2, L/2, Ny)
    X, Y = np.meshgrid(x, y)

    fig = plt.figure(figsize=(9, 6))
    ax = fig.add_subplot(111, projection="3d")

    surf = ax.plot_surface(
        X, Y, Z,
        cmap="ocean",
        edgecolor="none",
        linewidth=0,
        antialiased=True,
        rstride=stride,
        cstride=stride
    )

    ax.set_title(title)
    ax.set_xlabel("x")
    ax.set_ylabel("y")
    ax.set_zlabel("height")

    if zlim is not None:
        ax.set_zlim(*zlim)

    ax.view_init(elev=35, azim=-60)
    fig.colorbar(surf, ax=ax, shrink=0.6, aspect=12, label="height")
    plt.show()


def relative_error(a, b):
    a = np.asarray(a)
    b = np.asarray(b)
    return np.linalg.norm(a - b) / (np.linalg.norm(b) + 1e-12)


def is_power_of_two(N):
    return N > 0 and (N & (N - 1)) == 0


# ─────────────────────────────────────────────────────────────────────────────
# Section 2 — Frequency / Wavenumber Grid Helpers (used by Tasks 5–7)
# ─────────────────────────────────────────────────────────────────────────────

def _frequency_indices(N):
    """DFT bin indices: [0, 1, …, N/2-1, -N/2, …, -1] for even N."""
    return np.concatenate([np.arange(0, N // 2), np.arange(-N // 2, 0)])


def _make_wavenumber_grid(N, L=10.0):
    """Return KX, KY grids in rad/unit-length for an L-by-L domain."""
    k = 2 * np.pi * _frequency_indices(N) / L
    return np.meshgrid(k, k)


# ─────────────────────────────────────────────────────────────────────────────
# Section 3 — Test Surface Generator
# ─────────────────────────────────────────────────────────────────────────────

def make_ocean_surface(N=64, L=10.0, seed=0, target_std=0.12):
    """
    Build a calm 2D surface by summing low-frequency 2D sinusoids.
    This function does not use FFT; it only creates a test surface.
    """
    rng = np.random.default_rng(seed)

    x = np.arange(N)
    y = np.arange(N)
    X, Y = np.meshgrid(x, y)

    Z = np.zeros((N, N), dtype=float)

    components = [
        (2, 1), (1, 3), (3, 2), (-1, 2),
        (2, -1), (1, 1), (-2, 3), (3, -1)
    ]

    for fx, fy in components:
        amp = rng.uniform(0.05, 0.18)
        phi = rng.uniform(0, 2 * np.pi)
        Z += amp * np.cos(2 * np.pi * (fx * X / N + fy * Y / N) + phi)

    std = np.std(Z)
    if std > 1e-12:
        Z = Z / std * target_std

    return Z


def centered_2d(A):
    """fftshift-like centering for visualisation only."""
    A = np.asarray(A)
    return np.roll(np.roll(A, A.shape[0] // 2, axis=0), A.shape[1] // 2, axis=1)


def plot_2d_spectrum(H, title="2D magnitude spectrum"):
    mag = np.log1p(np.abs(centered_2d(H)))
    plt.figure(figsize=(6, 5))
    plt.imshow(mag, cmap="magma", origin="lower")
    plt.colorbar(label="log(1 + |H[kx,ky]|)")
    plt.title(title)
    plt.xlabel("centered kx bin")
    plt.ylabel("centered ky bin")
    plt.show()


