def validate_task1(my_dft, my_idft):
    """
    Task 1.2 — Validate the student's my_dft / my_idft against numpy's FFT.
    Call as:  validate_task1(my_dft, my_idft)
    """
    print("=" * 45)
    print("Task 1.2 Validation — DFT / IDFT")
    print("=" * 45)

    test_cases = {
        "Impulse":       np.array([1, 0, 0, 0, 0, 0, 0, 0]),
        "Constant (DC)": np.ones(8),
        "Sine Wave":     np.sin(2 * np.pi * 2 * np.linspace(0, 1, 8, endpoint=False)),
        "Random Noise":  np.random.default_rng(42).normal(size=16),
    }

    all_pass = True
    for name, x in test_cases.items():
        X_student = my_dft(x)
        X_ref     = np.fft.fft(x)
        dft_pass  = np.allclose(X_student, X_ref, atol=1e-10)

        x_student = my_idft(X_student)
        idft_pass = np.allclose(x_student, x, atol=1e-10)

        status = "PASS" if (dft_pass and idft_pass) else "FAIL"
        if status == "FAIL":
            all_pass = False
        print(f"  {name:15s}: {status}")

    print()
    if all_pass:
        print("All Task 1 tests passed.")
    else:
        print("Some Task 1 tests FAILED — check your implementation.")


def validate_task3(my_fft, my_ifft):
    """
    Task 3.4 — Validate the student's my_fft / my_ifft against numpy's FFT.
    Call as:  validate_task3(my_fft, my_ifft)
    """
    print("=" * 45)
    print("Task 3.4 Validation — FFT / IFFT")
    print("=" * 45)

    rng = np.random.default_rng(42)
    all_pass = True

    for N_test in [2, 4, 8, 16, 64, 128]:
        x         = rng.normal(size=N_test) + 1j * rng.normal(size=N_test)
        X_student = my_fft(x)
        X_ref     = np.fft.fft(x)
        fft_err   = np.max(np.abs(X_student - X_ref))

        x_recon   = my_ifft(X_student)
        recon_err = np.max(np.abs(x_recon - x))

        status = "PASS" if fft_err < 1e-8 and recon_err < 1e-8 else "FAIL"
        if status == "FAIL":
            all_pass = False
        print(f"  N={N_test:4d}  {status}")

    # Known-signal checks
    print()
    print("Known-signal checks:")

    x_imp = np.zeros(8); x_imp[0] = 1.0
    imp_ok = np.allclose(my_fft(x_imp), np.ones(8))
    print(f"  Impulse  → all-ones spectrum : {'PASS' if imp_ok else 'FAIL'}")
    if not imp_ok:
        all_pass = False

    x_dc = np.ones(8)
    X_dc = my_fft(x_dc)
    dc_ok = np.isclose(X_dc[0], 8.0) and np.allclose(X_dc[1:], 0, atol=1e-10)
    print(f"  DC       → spike at k=0      : {'PASS' if dc_ok else 'FAIL'}")
    if not dc_ok:
        all_pass = False

    print()
    if all_pass:
        print("All Task 3 tests passed.")
    else:
        print("Some Task 3 tests FAILED — check your implementation.")


def validate_task4(my_fft2, my_ifft2):
    """
    Task 4.3 — Validate the student's my_fft2 / my_ifft2.
    Call as:  validate_task4(my_fft2, my_ifft2)
    """
    print("=" * 45)
    print("Task 4.3 Validation — 2D FFT / IFFT")
    print("=" * 45)

    rng = np.random.default_rng(42)
    all_pass = True

    for size in [4, 8, 16, 32]:
        A         = rng.normal(size=(size, size)) + 1j * rng.normal(size=(size, size))
        A_student = my_fft2(A)
        A_ref     = np.fft.fft2(A)
        fft_err   = np.max(np.abs(A_student - A_ref))

        A_recon   = my_ifft2(A_student)
        recon_err = np.max(np.abs(A_recon - A))

        status = "PASS" if fft_err < 1e-8 and recon_err < 1e-8 else "FAIL"
        if status == "FAIL":
            all_pass = False
        print(f"  {size:2d}×{size:2d}  {status}")

    print()
    if all_pass:
        print("All Task 4 tests passed.")
    else:
        print("Some Task 4 tests FAILED — check your implementation.")


